 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import {
 4	  DescriptionListDescription,
 5	  DescriptionListGroup,
 6	  DescriptionListTerm,
 7	} from '@patternfly/react-core';
 8	import { PipelineRunWorkspace } from '../../types';
 9	
10	type EmptyDirectoriesSectionProps = {
11	  workspaces: PipelineRunWorkspace[];
12	};
13	
14	const EmptyDirectoriesSection: React.FC<EmptyDirectoriesSectionProps> = ({
15	  workspaces,
16	}) => {
17	  const { t } = useTranslation('plugin__pipelines-console-plugin');
18	
19	  if (!workspaces || workspaces.length === 0) return null;
20	
21	  const emptyDirectoryWorkspaces = workspaces.filter(
22	    (workspace) => !!workspace.emptyDir,
23	  );
24	  if (emptyDirectoryWorkspaces.length === 0) return null;
25	
26	  return (
27	    <DescriptionListGroup data-test-id="empty-directories-section">
28	      <DescriptionListTerm>{t('Empty Directories')}</DescriptionListTerm>
29	      <DescriptionListDescription>
30	        {emptyDirectoryWorkspaces.map((workspace) => (
31	          <div key={workspace.name} data-test-id="empty-directory-workspace">
32	            {t(`Empty Directory ({{workspaceName}})`, {
33	              workspaceName: workspace.name,
34	            })}
35	          </div>
36	        ))}
37	      </DescriptionListDescription>
38	    </DescriptionListGroup>
39	  );
40	};
41	
42	export default EmptyDirectoriesSection;

